import React, { useState } from 'react';
import Drawer from '@material-ui/core/Drawer';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import AddIcon from '@material-ui/icons/Add';
import DeleteIcon from '@material-ui/icons/Delete';
import IconButton from '@material-ui/core/IconButton';
import MenuIcon from '@material-ui/icons/Menu';
import { Link } from 'react-router-dom';
import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  mainMenuContainer: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(20%, 1fr))', // Justera beroende på det önskade antalet huvudmenyval per rad
    gap: theme.spacing(2),
  },
  menuItemContainer: {
    marginBottom: theme.spacing(2), // Justera marginalsparningen som behövs
  },
  menuItemLastInRow: {
    gridColumn: 'span 2', // Justera beroende på det önskade antalet kolumner per rad
  },
  mainMenuItem: {
    fontSize: '1.2rem',
    paddingTop: 1,
    paddingBottom: 1,
  },
  subMenuItem: {
    fontSize: '1rem',
    paddingTop: 1,
    paddingBottom: 1,
    paddingLeft: theme.spacing(2), // Adjust the left padding as needed
  },
  iconButton: {
    marginLeft: theme.spacing(1), // Adjust the left margin as needed
  },
}));

const DrawerMenu = ({ categories }) => {
  const classes = useStyles();
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);

  const handleDrawerOpen = () => {
    setIsDrawerOpen(true);
  };

  const handleDrawerClose = () => {
    setIsDrawerOpen(false);
  };

  const generateMenuItems = () => {
    if (!Array.isArray(categories) || categories.length === 0) {
      return null;
    }

    const calculateGridColumns = (subMenuLength) => {
      const maxColumns = 5; // Maximalt antal kolumner per rad för huvudmenyval
      return subMenuLength > maxColumns ? maxColumns : subMenuLength;
    };

    const flattenSubMenu = (subMenu) => {
      return Array.isArray(subMenu) ? subMenu.reduce((acc, val) => acc.concat(val), []) : [];
    };

    return (
      <List className={classes.mainMenuContainer}>
        {categories.map((category) => {
        const { _id, mainMenu, subMenu } = category;

        if (!_id || !mainMenu) {
          return null;
        }

        const subMenuItems = flattenSubMenu(subMenu);
        const subMenuLength = subMenuItems.length;
        const gridColumnValue = calculateGridColumns(subMenuLength);

        return (
          <div
            key={_id}
            className={`${classes.menuItemContainer} ${
              gridColumnValue > 1 ? classes.menuItemMultiColumn : ''
            }`}
            style={{ gridColumn: `span ${gridColumnValue}` }}
          >
              <ListItem button component={Link} to={`/${mainMenu}`} onClick={handleDrawerClose} className={classes.mainMenuItem}>
                <ListItemText primary={mainMenu} />
                <div>
                  <IconButton className={classes.iconButton}>
                    <AddIcon />
                  </IconButton>
                  <IconButton className={classes.iconButton}>
                    <DeleteIcon />
                  </IconButton>
                </div>
              </ListItem>
              {Array.isArray(subMenu) && subMenu.length > 0 && (
                <List component="div" disablePadding>
                  {subMenu.map((subItem) => {
                    if (!subItem) {
                      return null;
                    }

                    const subItemId = subItem._id || ''; // handle null or undefined _id
                    const subItemText = subItem || '';

                    return (
                      <ListItem
                        key={subItemId}
                        button
                        component={Link}
                        to={`/${mainMenu}/${subItemId}`}
                        onClick={handleDrawerClose}
                        className={classes.subMenuItem} // Apply the subMenuItem style
                      >
                        <ListItemText primary={subItemText} />
                        <div>
                          <IconButton className={classes.iconButton}>
                            <DeleteIcon />
                          </IconButton>
                        </div>
                      </ListItem>
                    );
                  })}
                </List>
              )}
            </div>
          );
        })}
      </List>
    );
  };


  return (
    <div>
      <IconButton
        edge="start"
        color="inherit"
        aria-label="menu"
        onClick={handleDrawerOpen}
      >
        <MenuIcon />
      </IconButton>
      <Drawer anchor="top" open={isDrawerOpen} onClose={handleDrawerClose}>
        {generateMenuItems()}
      </Drawer>
    </div>
  );
};

export default DrawerMenu;
